using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// 2a. With the default (reflection-based) resolver, any serializable type resolves:
if (options.TryGetTypeInfo<Person>(out var info))
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded → {info!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> returned false");

// 2b. With a source-gen context that only knows about Person,
//     querying for an unknown type returns false instead of throwing:
var restricted = new JsonSerializerOptions { TypeInfoResolver = MyContext.Default };

if (restricted.TryGetTypeInfo<int[]>(out var arrayInfo))
    Console.WriteLine($"TryGetTypeInfo<int[]> succeeded → {arrayInfo!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<int[]> returned false (not in source-gen context)");

// A type the restricted context *does* know about:
if (restricted.TryGetTypeInfo<Person>(out var personInfo2))
    Console.WriteLine($"TryGetTypeInfo<Person> on restricted context succeeded → {personInfo2!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> on restricted context returned false");

// --- Types & source-gen context ---
public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class MyContext : JsonSerializerContext;

